// Only keep PRs that: actually merged (not just closed), merged after
// the last timestamp we processed, and merged into main (already
// filtered by the API query, double-checked here defensively).
const lastCheckedRow = $('Get Last Checked Timestamp').first();
const lastChecked = new Date(lastCheckedRow.json.value);

const prs = $input.all().map(i => i.json);
const newlyMerged = prs.filter(pr =>
  pr.merged_at !== null &&
  new Date(pr.merged_at) > lastChecked &&
  pr.base.ref === 'main'
);

if (newlyMerged.length === 0) {
  return []; // nothing new -- downstream nodes simply won't run
}

return newlyMerged.map(pr => ({
  json: {
    repo_full_name: pr.base.repo.full_name,
    pr_number: pr.number,
    merge_commit_sha: pr.merge_commit_sha,
    merged_at: pr.merged_at
  }
}));

// Re-attach PR context to each matching file, since the files
// endpoint response doesn't carry it.
const prCtxList = $('Filter Newly Merged').all().map(i => i.json);

const results = [];
for (const item of $input.all()) {
  const filename = item.json.filename;
  const match = filename.match(/^agents\/([a-z0-9-]+)\/agent\.yaml$/);
  if (!match) continue;

  // Find which PR this file result belongs to by matching against
  // the pairedItem index n8n tracks automatically.
  const prCtx = prCtxList[item.pairedItem.item];
  results.push({
    json: {
      agent_id: match[1],
      filename,
      repo_full_name: prCtx.repo_full_name,
      pr_number: prCtx.pr_number,
      merge_commit_sha: prCtx.merge_commit_sha,
      merged_at: prCtx.merged_at
    }
  });
}
return results;

const reviews = $input.all().map(i => i.json);
const approvals = reviews.filter(r => r.state === 'APPROVED');
if (approvals.length === 0) {
  throw new Error('No approved review found on this PR -- refusing to promote an unapproved merge');
}
approvals.sort((a, b) => new Date(b.submitted_at) - new Date(a.submitted_at));
const approver = approvals[0].user.login;

const ctx = $('Filter Changed agent.yaml Files').first().json;
return [{ json: { ...ctx, approver } }];

const crypto = require('crypto');
const ctx = $('Pick Latest Approver').first().json;
const content = $input.first().json.data || $input.first().json;
const hash = crypto.createHash('sha256').update(content, 'utf8').digest('hex');

return [{
  json: {
    agent_id: ctx.agent_id,
    git_commit: ctx.merge_commit_sha,
    content_hash: hash,
    approver: ctx.approver,
    raw_content: content,
    merged_at: ctx.merged_at
  }
}];
